commonPatterns.pattern:
import { create } from 'zustand';

const useMyStore = create((set, get) => ({
  // State
  data: initialValue,

  // Actions
  updateData: (newData) => set({ data: newData }),
  complexAction: () => {
    set(state => ({
      data: processedData
    }));
  },
}));

return items.filter((item) => {
  if (filters.condition1 && !passes(item, filters.condition1)) return false;
  if (filters.condition2 && !passes(item, filters.condition2)) return false;
  // ... more conditions
  return true; // All passed
});

const [searchTerm, setSearchTerm] = useState('');
const debouncedSearch = useDebounce(searchTerm, 300);

useEffect(() => {
  setFilters({ searchTerm: debouncedSearch });
}, [debouncedSearch]);

.container {
  display: flex;
  flex-direction: column; /* Mobile default */
}

@media (min-width: 640px) {
  .container {
    flex-direction: row; /* Tablet and up */
  }
}

@media (min-width: 1024px) {
  .container {
    display: grid; /* Desktop */
  }
}

const handleRejudge = (submissionId, newVerdict) => {
  // 1. Update submission
  submissionStore.updateVerdictBySubmissionId(submissionId, newVerdict);

  // 2. Update participant (get from submission)
  const submission = submissionStore.getSubmission(submissionId);
  const delta = calculateDelta(oldVerdict, newVerdict);
  participantStore.updateParticipantScore(submission.participantId, delta);

  // 3. Recalculate (if not frozen)
  if (!uiStore.getState().isFrozen) {
    participantStore.recalculateRankings();
  }

  // 4. Log activity
  activityStore.logActivity(ActivityType.SubmissionRejudged, ...);
};

